const SECTOR_NAME_TO_ID = Object.fromEntries(
  Object.entries(SECTOR_TRANSLATIONS.es).map(([id, label]) => [label, id]),
);

export const translateSector = (language, sectorValue = '') => {
  const safeValue = String(sectorValue || '').trim();
  if (!safeValue) return translate(language, 'detail_no_sector');

  const sectorId = SECTOR_TRANSLATIONS.es[safeValue] ? safeValue : (SECTOR_NAME_TO_ID[safeValue] || safeValue);
  return (
    SECTOR_TRANSLATIONS[language]?.[sectorId] ||
    SECTOR_TRANSLATIONS.en?.[sectorId] ||
    SECTOR_TRANSLATIONS.es?.[sectorId] ||
    safeValue
  );
};

export const translateStatus = (language, statusValue = '') => {
  const safeValue = String(statusValue || '').trim();
  if (!safeValue) return safeValue;

  return (
    STATUS_TRANSLATIONS[language]?.[safeValue] ||
    STATUS_TRANSLATIONS.en?.[safeValue] ||
    STATUS_TRANSLATIONS.es?.[safeValue] ||
    safeValue
  );
};

export const translate = (language, key) => DICT[language]?.[key] || DICT.en?.[key] || DICT.es[key] || key;
